import React, { useEffect, useState, useRef } from "react";
import "../App.css";
import FanDial from "./FanDial";
import { getStatus, postLight, postFan, postUpdate, API_BASE } from "../api";
import WebSocketClient from "../utils/WebSocketClient";
import WeatherAnim from "./WeatherAnim";

const WS_URL = process.env.REACT_APP_WS_URL || "ws://localhost:5000";

export default function Dashboard({ user, selectedProfile }) {
  const [state, setState] = useState({
    lightOn: false,
    fanSpeed: 0,
    tankLevel: 0,
    pumpOn: false,
    smokeDetected: false,
    climate: { tempC: "--", humidity: "--" }
  });
  const [connected, setConnected] = useState(false);
  const wsRef = useRef(null);
  const lastNonZeroSpeed = useRef(3); // default fallback speed when turning fan on

  useEffect(() => {
    if (!user) return;
    getStatus().then(d => {
      setState(s => ({ ...s, ...d }));
      if (d.fanSpeed && d.fanSpeed > 0) lastNonZeroSpeed.current = d.fanSpeed;
    }).catch(e => console.warn("Initial status failed:", e));
  }, [user]);

  // WebSocket subscription
  useEffect(() => {
    if (!user) return;
    const ws = new WebSocketClient(WS_URL);
    wsRef.current = ws;
    ws.connect();

    const unsub = ws.subscribe((msg) => {
      if (!msg) return;
      if (msg.type === "ws_open") { setConnected(true); return; }
      if (msg.type === "ws_close") { setConnected(false); return; }
      if (msg.type === "status_update" || msg.type === "state") {
        setState(s => ({ ...s, ...msg }));
        if (msg.fanSpeed && msg.fanSpeed > 0) lastNonZeroSpeed.current = msg.fanSpeed;
      }
      if (msg.type === "device") {
        if (msg.device === "fan") {
          setState(s => ({ ...s, fanSpeed: msg.speed }));
          if (msg.speed > 0) lastNonZeroSpeed.current = msg.speed;
        }
        if (msg.device === "light") setState(s => ({ ...s, lightOn: msg.state }));
      }
      if (msg.type === "sensor") {
        setState(s => ({ ...s, climate: { tempC: msg.temperature, humidity: msg.humidity }, tankLevel: msg.tankLevel, smokeDetected: msg.smokeDetected }));
      }
    });

    return () => unsub();
  }, [user]);

  const changeFanSpeed = (speed) => {
    if (!user) return;
    postFan(speed).catch(e => console.warn("Failed to set fan speed:", e));
  };

  const toggleFanPower = () => {
    if (!user) return;
    const newSpeed = state.fanSpeed > 0 ? 0 : lastNonZeroSpeed.current;
    postFan(newSpeed).catch(e => console.warn("Failed to toggle fan power:", e));
  };

  const toggleLight = () => {
    if (!user) return;
    postLight(!state.lightOn).catch(e => console.warn("Failed to toggle light:", e));
  };

  const resetSmoke = () => {
    if (!user) return;
    postUpdate({ smokeDetected: false }).catch(e => console.warn("Failed to reset smoke alarm:", e));
  };

  const smokeClass = state.smokeDetected ? "smoke-alert" : "smoke-safe";
  const pumpClass = state.pumpOn ? "pump-on" : "pump-off";

  return (
    <div className="App">
      <header className="App-header">
        <h1>Smart Home Dashboard</h1>
        <div className="header-info">
          <span>Profile: {selectedProfile?.name || 'Default'}</span>
          <span>Connected: {connected ? '✅' : '❌'}</span>
        </div>
      </header>

      <main>
        {/* Climate */}
        <section className="card">
          <div className="card-title">Climate</div>
          <WeatherAnim temp={state.climate.tempC} humidity={state.climate.humidity} />
        </section>

        {/* Light Control */}
        <section className="card">
          <div className="card-title">Light</div>
          <button className={`btn ${state.lightOn ? "btn-on" : "btn-off"}`} onClick={toggleLight}>
            {state.lightOn ? "Turn Off" : "Turn On"}
          </button>
        </section>

        {/* Fan Control */}
        <section className="card">
          <div className="card-title">Fan</div>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-around", gap: 12 }}>
            <FanDial value={state.fanSpeed} onChange={changeFanSpeed} size={170} />
            <div style={{ display: "flex", flexDirection: "column", gap: 10, minWidth: 140 }}>
              <button
                className={`btn ${state.fanSpeed > 0 ? "btn-on" : "btn-off"}`}
                onClick={toggleFanPower}
              >
                {state.fanSpeed > 0 ? "Fan OFF" : "Fan ON"}
              </button>
              <div style={{ textAlign: "center", color: "#9fb3d6", fontSize: 13 }}>
                Current: <strong style={{ color: "#fff" }}>{state.fanSpeed}</strong>
              </div>
            </div>
          </div>
          <div className="hint">Drag the dial or use the buttons to control fan speed (0–5)</div>
        </section>

        {/* Safety & Water */}
        <section className="card">
          <div className="card-title">Safety & Water</div>
          <div className="row">
            <div className="subcard">
              <div className="sub-title">Water Tank</div>
              {/* animated water tank */}
              <div className="water-tank" aria-hidden>
                <div className="water" style={{ height: `${state.tankLevel ?? 0}%` }} />
                <div className="tank-overlay">
                  <div className="tank-label">Filled: {state.tankLevel ?? 0}%</div>
                </div>
              </div>
              <div style={{ marginTop: 8 }}>
                <div className={`chip ${pumpClass}`}>Pump {state.pumpOn ? "ON" : "OFF"}</div>
              </div>
            </div>
            <div className="subcard">
              <div className="sub-title">Smoke</div>
              <div className={`big-status ${smokeClass}`} style={{ marginBottom: 8 }}>
                {state.smokeDetected ? "SMOKE DETECTED 🚨" : "SAFE ✅"}
              </div>
              <button
                className="btn btn-off"
                onClick={resetSmoke}
                disabled={!state.smokeDetected}
                title={state.smokeDetected ? "Reset alarm" : "No alarm to reset"}
                style={{ opacity: state.smokeDetected ? 1 : 0.5, cursor: state.smokeDetected ? "pointer" : "not-allowed" }}
              >
                Reset Smoke Alarm
              </button>
            </div>
          </div>
        </section>
      </main>
      <footer className="footer">© Smart Home by Team Alpha</footer>
    </div>
  );
}
